function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const maxVal = 10000;

    const valueMap: [number, number][][] = Array.from({ length: maxVal + 1 }, () => []);
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            if (val <= maxVal) {
                valueMap[val].push([i, j]);
            }
        }
    }

    const layers = k + 1;
    const dist: number[][][] = Array(layers);
    for (let t = 0; t < layers; t++) {
        dist[t] = Array(m);
        for (let i = 0; i < m; i++) {
            dist[t][i] = Array(n).fill(Number.MAX_SAFE_INTEGER);
        }
    }
    dist[0][0][0] = 0;

    const teleportMin: number[][] = Array(layers);
    for (let t = 0; t < layers; t++) {
        teleportMin[t] = Array(maxVal + 1).fill(Number.MAX_SAFE_INTEGER);
    }

    type HeapItem = [cost: number, t: number, i: number, j: number];
    const heap: HeapItem[] = [];

    function heapPush(item: HeapItem): void {
        heap.push(item);
        let idx = heap.length - 1;
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            if (heap[parentIdx][0] <= heap[idx][0]) break;
            [heap[parentIdx], heap[idx]] = [heap[idx], heap[parentIdx]];
            idx = parentIdx;
        }
    }

    function heapPop(): HeapItem {
        const top = heap[0];
        const last = heap.pop()!;
        if (heap.length > 0) {
            heap[0] = last;
            let idx = 0;
            while (true) {
                const left = 2 * idx + 1;
                const right = 2 * idx + 2;
                let smallest = idx;
                if (left < heap.length && heap[left][0] < heap[smallest][0]) {
                    smallest = left;
                }
                if (right < heap.length && heap[right][0] < heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest === idx) break;
                [heap[idx], heap[smallest]] = [heap[smallest], heap[idx]];
                idx = smallest;
            }
        }
        return top;
    }

    heapPush([0, 0, 0, 0]);

    const directions: [number, number][] = [[0, 1], [1, 0]];

    while (heap.length > 0) {
        const [cost, t, i, j] = heapPop();
        if (cost !== dist[t][i][j]) continue;

        for (const [dx, dy] of directions) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) continue;
            const newCost = cost + grid[ni][nj];
            if (newCost < dist[t][ni][nj]) {
                dist[t][ni][nj] = newCost;
                heapPush([newCost, t, ni, nj]);
            }
        }

        if (t < k) {
            const g = grid[i][j];
            let v = Math.min(g, maxVal);
            while (v >= 0) {
                if (cost < teleportMin[t][v]) {
                    teleportMin[t][v] = cost;
                    for (const [x, y] of valueMap[v]) {
                        if (cost < dist[t + 1][x][y]) {
