                            heapPush([cost, t + 1, x, y]);
                        }
                    }
                    v--;
                } else {
                    break;
                }
            }
        }
    }

    let ans = Number.MAX_SAFE_INTEGER;
    for (let t = 0; t < layers; t++) {
        if (dist[t][m - 1][n - 1] < ans) {
            ans = dist[t][m - 1][n - 1];
        }
    }
    return ans;
}
